#!/usr/bin/env node

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import fs from "fs";
import path from "path";

const API_KEY = process.env.GRSAI_API_KEY;
const API_BASE = process.env.GRSAI_API_BASE || "https://grsai.dakka.com.cn";
const SAVE_DIR = process.env.GRSAI_SAVE_DIR || "D:\\ClaudeWorkspace\\01_P4P\\主图素材";

if (!API_KEY) {
  console.error("ERROR: GRSAI_API_KEY environment variable is required");
  process.exit(1);
}

if (!fs.existsSync(SAVE_DIR)) {
  fs.mkdirSync(SAVE_DIR, { recursive: true });
}

const server = new Server(
  { name: "grsai-image", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

function ts() {
  const n = new Date();
  return `${n.getFullYear()}${String(n.getMonth()+1).padStart(2,"0")}${String(n.getDate()).padStart(2,"0")}_${String(n.getHours()).padStart(2,"0")}${String(n.getMinutes()).padStart(2,"0")}${String(n.getSeconds()).padStart(2,"0")}`;
}

function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "generate_image",
      description: "使用 GrsAI 生成图像（Nano Banana 系列模型）",
      inputSchema: {
        type: "object",
        properties: {
          model: {
            type: "string",
            description: "模型: nano-banana, nano-banana-pro, nano-banana-2, nano-banana-fast",
            default: "nano-banana",
          },
          prompt: {
            type: "string",
            description: "图像描述提示词（越详细效果越好）",
          },
          aspectRatio: {
            type: "string",
            description: "画面比例: 1:1, 16:9, 9:16, 4:3, 3:4",
            default: "1:1",
          },
          filename: {
            type: "string",
            description: "保存文件名前缀（不含扩展名），默认自动生成",
          },
        },
        required: ["prompt"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "generate_image") {
    throw new Error(`Unknown tool: ${request.params.name}`);
  }

  const args = request.params.arguments;
  const model = args.model || "nano-banana";
  const prompt = args.prompt;
  const aspectRatio = args.aspectRatio || "1:1";
  const filenamePrefix = args.filename || `grsai_${model.replace(/[^a-z0-9]/gi, "_")}`;

  if (!prompt) throw new Error("prompt is required");

  // Step 1: Submit task
  const submitUrl = `${API_BASE}/v1/draw/${model}`;
  const submitRes = await fetch(submitUrl, {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${API_KEY}` },
    body: JSON.stringify({ model, prompt, aspectRatio, webHook: "-1" }),
    signal: AbortSignal.timeout(30000),
  });

  const submitData = await submitRes.json();
  if (submitData.code !== 0 && submitData.code !== undefined) {
    throw new Error(`GrsAI error: ${submitData.msg || JSON.stringify(submitData)}`);
  }

  const taskId = submitData.id || submitData.data?.id;
  if (!taskId) throw new Error(`No task ID returned: ${JSON.stringify(submitData)}`);

  // Step 2: Poll for result
  let attempts = 0;
  const maxAttempts = 60;
  let resultData = null;

  while (attempts < maxAttempts) {
    await sleep(2000);

    const pollRes = await fetch(`${API_BASE}/v1/draw/result`, {
      method: "POST",
      headers: { "Content-Type": "application/json", Authorization: `Bearer ${API_KEY}` },
      body: JSON.stringify({ id: taskId }),
      signal: AbortSignal.timeout(15000),
    });

    const pollData = await pollRes.json();

    if (pollData.progress === 100 || pollData.status === "completed" || pollData.status === "success") {
      resultData = pollData;
      break;
    }

    if (pollData.status === "failed" || pollData.status === "error") {
      throw new Error(`Generation failed: ${pollData.failure_reason || pollData.msg || "unknown"}`);
    }

    attempts++;
  }

  if (!resultData) throw new Error("Timeout waiting for image generation");

  // Step 3: Download images
  const images = resultData.results || [];
  if (images.length === 0) throw new Error("No images in result");

  const savedPaths = [];
  for (let i = 0; i < images.length; i++) {
    const imgUrl = images[i].url;
    if (!imgUrl) continue;

    const imgRes = await fetch(imgUrl);
    const imgBuffer = Buffer.from(await imgRes.arrayBuffer());
    const ext = imgUrl.includes(".png") ? "png" : "jpg";
    const fileName = `${filenamePrefix}_${ts()}${images.length > 1 ? `_${i + 1}` : ""}.${ext}`;
    const filePath = path.join(SAVE_DIR, fileName);
    fs.writeFileSync(filePath, imgBuffer);
    savedPaths.push(filePath);
  }

  return {
    content: [{ type: "text", text: JSON.stringify({ savedPaths, taskId }, null, 2) }],
  };
});

process.on("SIGINT", async () => {
  await server.close();
  process.exit(0);
});

const transport = new StdioServerTransport();
await server.connect(transport);

