if (!API_KEY) {
  console.error("ERROR: GRSAI_API_KEY environment variable is required");
  process.exit(1);
}

// Ensure save directory exists
if (!fs.existsSync(SAVE_DIR)) {
  fs.mkdirSync(SAVE_DIR, { recursive: true });
}

const server = new Server(
  { name: "grsai-image", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

function timestamp() {
  const now = new Date();
  return `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, "0")}${String(now.getDate()).padStart(2, "0")}_${String(now.getHours()).padStart(2, "0")}${String(now.getMinutes()).padStart(2, "0")}${String(now.getSeconds()).padStart(2, "0")}`;
}

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "generate_image",
      description: "使用 GrsAI 生成图像（支持 Nano Banana / Nano Banana Pro 等模型）",
      inputSchema: {
        type: "object",
        properties: {
          model: {
            type: "string",
            description: "模型: nano-banana, nano-banana-pro",
            default: "nano-banana",
          },
          prompt: {
            type: "string",
            description: "图像描述提示词（越详细效果越好）",
          },
          size: {
            type: "string",
            description: "画面比例: auto, 1:1, 3:2, 2:3",
            default: "1:1",
          },
          filename: {
            type: "string",
            description: "保存文件名前缀（不含扩展名），默认自动生成",
          },
        },
        required: ["prompt"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "generate_image") {
    throw new Error(`Unknown tool: ${request.params.name}`);
  }

  const args = request.params.arguments;
  const model = args.model || "nano-banana";
  const prompt = args.prompt;
  const size = args.size || "1:1";
  const filenamePrefix = args.filename || `grsai_${model.replace(/[^a-z0-9]/gi, "_")}`;

  if (!prompt) {
    throw new Error("prompt is required");
  }

  // Call GrsAI API
  const response = await fetch(`${API_BASE}/v1/draw/completions`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${API_KEY}`,
    },
    body: JSON.stringify({ model, prompt, size }),
    signal: AbortSignal.timeout(120000),
  });

  const result = await response.json();

  if (!response.ok) {
    throw new Error(`GrsAI API error: ${result.message || response.statusText}`);
  }

  // Parse response - download and save image
  let imageUrl = null;
  if (result.results && result.results[0]?.url) {
    imageUrl = result.results[0].url;
  } else if (result.data?.results?.[0]?.url) {
    imageUrl = result.data.results[0].url;
  } else if (result.url) {
    imageUrl = result.url;
  }

  let savedPath = null;
  let imageBase64 = null;

  if (imageUrl) {
    // Download the image
    const imgRes = await fetch(imageUrl);
    const imgBuffer = Buffer.from(await imgRes.arrayBuffer());

    // Save to file
    const ts = timestamp();
    const ext = imageUrl.includes(".png") ? "png" : "jpg";
    const fileName = `${filenamePrefix}_${ts}.${ext}`;
    const filePath = path.join(SAVE_DIR, fileName);
    fs.writeFileSync(filePath, imgBuffer);
    savedPath = filePath;

    // Also return as base64 for inline display
    imageBase64 = imgBuffer.toString("base64");
  }

  return {
    content: [
      { type: "text", text: JSON.stringify({ savedPath, ...result }, null, 2) },
    ],
  };
});

// Handle cleanup
process.on("SIGINT", async () => {
  await server.close();
  process.exit(0);
});

const transport = new StdioServerTransport();
await server.connect(transport);

