#!/usr/bin/env node

import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import {
  CallToolRequestSchema,
  ListToolsRequestSchema,
} from "@modelcontextprotocol/sdk/types.js";
import fs from "fs";
import path from "path";

const API_KEY = process.env.GRSAI_API_KEY;
const API_BASE = process.env.GRSAI_API_BASE || "https://grsai.dakka.com.cn";
const SAVE_DIR = process.env.GRSAI_SAVE_DIR || "D:\\ClaudeWorkspace\\01_P4P\\主图素材";

if (!API_KEY) { console.error("ERROR: GRSAI_API_KEY required"); process.exit(1); }
if (!fs.existsSync(SAVE_DIR)) fs.mkdirSync(SAVE_DIR, { recursive: true });

const server = new Server(
  { name: "grsai-image", version: "1.0.0" },
  { capabilities: { tools: {} } }
);

function ts() {
  const n = new Date();
  return `${n.getFullYear()}${String(n.getMonth()+1).padStart(2,"0")}${String(n.getDate()).padStart(2,"0")}_${String(n.getHours()).padStart(2,"0")}${String(n.getMinutes()).padStart(2,"0")}${String(n.getSeconds()).padStart(2,"0")}`;
}

async function sseFetch(url, body) {
  const res = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${API_KEY}` },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const text = await res.text();
    try {
      const j = JSON.parse(text);
      throw new Error(j.msg || j.message || text);
    } catch (e) {
      if (e.message !== text) throw e;
      throw new Error(`HTTP ${res.status}: ${text}`);
    }
  }

  // Parse SSE stream
  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    buffer += decoder.decode(value, { stream: true });

    const lines = buffer.split("\n");
    buffer = lines.pop() || "";

    for (const line of lines) {
      if (!line.startsWith("data: ")) continue;
      const jsonStr = line.slice(6);
      if (!jsonStr) continue;
      const data = JSON.parse(jsonStr);

      if (data.status === "failed" || data.status === "error") {
        throw new Error(data.failure_reason || data.error || "Generation failed");
      }
      if (data.status === "succeeded" && data.results?.length > 0) {
        return data;
      }
    }
  }
  throw new Error("Stream ended without result");
}

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [
    {
      name: "generate_image",
      description: "使用 GrsAI 生成图像（Nano Banana / GPT Image 等模型）",
      inputSchema: {
        type: "object",
        properties: {
          model: {
            type: "string",
            description: "模型: nano-banana, nano-banana-pro, gpt-image-2 等",
            default: "nano-banana",
          },
          prompt: { type: "string", description: "图像描述提示词" },
          aspectRatio: {
            type: "string", description: "比例: 1:1, 16:9, 9:16, 4:3, 3:4",
            default: "1:1",
          },
          filename: {
            type: "string", description: "文件名前缀，默认自动生成",
          },
        },
        required: ["prompt"],
      },
    },
  ],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name !== "generate_image") {
    throw new Error(`Unknown tool: ${request.params.name}`);
  }

  const args = request.params.arguments;
  const model = args.model || "nano-banana";
  const prompt = args.prompt;
  const aspectRatio = args.aspectRatio || "1:1";
  const prefix = args.filename || `grsai_${model.replace(/[^a-z0-9]/gi, "_")}`;
  if (!prompt) throw new Error("prompt is required");

  // Determine endpoint based on model
  const isPathModel = ["nano-banana", "nano-banana-pro", "nano-banana-2", "nano-banana-fast"].includes(model);
  const url = isPathModel
    ? `${API_BASE}/v1/draw/${model}`
    : `${API_BASE}/v1/draw/completions`;

  const body = isPathModel
    ? { model, prompt, aspectRatio }
    : { model, prompt, size: aspectRatio };

  const result = await sseFetch(url, body);

  // Download images
  const savedPaths = [];
  for (const img of (result.results || [])) {
    const imgUrl = img.url || img.image;
    if (!imgUrl) continue;

