const sharp = require("sharp");
const fs = require("fs");
const path = require("path");

async function analyzeImage(filePath) {
  const meta = await sharp(filePath).metadata();
  const { width, height } = meta;
  console.log(`\n========== ${path.basename(filePath)} ==========`);
  console.log(`尺寸: ${width} x ${height}`);
  console.log(`格式: ${meta.format}`);
  console.log(`色彩空间: ${meta.space}`);

  // Sample pixels in a grid to get color distribution
  const gridX = 20, gridY = 20;
  const stepX = Math.floor(width / gridX);
  const stepY = Math.floor(height / gridY);

  const raw = await sharp(filePath)
    .raw()
    .toBuffer();

  const pixels = [];
  for (let gy = 0; gy < gridY; gy++) {
    for (let gx = 0; gx < gridX; gx++) {
      const px = gx * stepX + Math.floor(stepX / 2);
      const py = gy * stepY + Math.floor(stepY / 2);
      const idx = (py * width + px) * 3;
      if (idx + 2 < raw.length) {
        pixels.push({ r: raw[idx], g: raw[idx + 1], b: raw[idx + 2], x: px, y: py });
      }
    }
  }

  // Color clusters (simple quantization)
  function colorBucket(c) {
    const r = Math.round(c.r / 64) * 64;
    const g = Math.round(c.g / 64) * 64;
    const b = Math.round(c.b / 64) * 64;
    return `${r},${g},${b}`;
  }

  const buckets = {};
  for (const p of pixels) {
    const key = colorBucket(p);
    if (!buckets[key]) buckets[key] = { count: 0, r: 0, g: 0, b: 0, positions: [] };
    buckets[key].count++;
    buckets[key].r += p.r;
    buckets[key].g += p.g;
    buckets[key].b += p.b;
    buckets[key].positions.push({ x: p.x, y: p.y });
  }

  const sorted = Object.entries(buckets)
    .map(([key, val]) => ({
      color: `rgb(${Math.round(val.r / val.count)},${Math.round(val.g / val.count)},${Math.round(val.b / val.count)})`,
      ratio: (val.count / pixels.length * 100).toFixed(1),
      positions: val.positions,
    }))
    .sort((a, b) => b.ratio - a.ratio);

  console.log("\n--- 主色调分布 ---");
  sorted.slice(0, 8).forEach((c) => {
    console.log(`  ${c.color} 占比 ${c.ratio}%`);
  });

  // Detect horizontal and vertical lines (edge regions)
  console.log("\n--- 结构分析 ---");

  // Analyze top/bottom/middle bands for layout
  const bands = [
    { name: "顶部(top 0-20%)", yStart: 0, yEnd: Math.floor(height * 0.2) },
    { name: "中上(mid-top 20-40%)", yStart: Math.floor(height * 0.2), yEnd: Math.floor(height * 0.4) },
    { name: "中部(mid 40-60%)", yStart: Math.floor(height * 0.4), yEnd: Math.floor(height * 0.6) },
    { name: "中下(mid-bottom 60-80%)", yStart: Math.floor(height * 0.6), yEnd: Math.floor(height * 0.8) },
    { name: "底部(bottom 80-100%)", yStart: Math.floor(height * 0.8), yEnd: height },
  ];

  for (const band of bands) {
    const bandPixels = pixels.filter(p => p.y >= band.yStart && p.y < band.yEnd);
    if (bandPixels.length === 0) continue;
    const avgR = Math.round(bandPixels.reduce((s, p) => s + p.r, 0) / bandPixels.length);
    const avgG = Math.round(bandPixels.reduce((s, p) => s + p.g, 0) / bandPixels.length);
    const avgB = Math.round(bandPixels.reduce((s, p) => s + p.b, 0) / bandPixels.length);
    console.log(`  ${band.name}: 平均色 rgb(${avgR},${avgG},${avgB})`);
  }

  // Detect white/empty regions (background)
  const whiteThreshold = 220;
  const whitePixels = pixels.filter(p => p.r > whiteThreshold && p.g > whiteThreshold && p.b > whiteThreshold);
  const whiteRatio = (whitePixels.length / pixels.length * 100).toFixed(1);
  console.log(`  白色/背景区域: ${whiteRatio}%`);

  // Detect likely annotation circles (looking for clustered non-white circular regions near edges)
  // Sample border pixels to detect frames/circles
  const borderPixels = pixels.filter(p => {
    const edgeDist = Math.min(p.x, p.y, width - p.x, height - p.y);
    return edgeDist < 30;
  });
  const nonWhiteBorder = borderPixels.filter(p => p.r < 200 || p.g < 200 || p.b < 200);
  console.log(`  边框区域非白色像素: ${nonWhiteBorder.length}/${borderPixels.length}`);

  // Detect colored annotation elements (saturated colors)
  const saturated = pixels.filter(p => {
    const max = Math.max(p.r, p.g, p.b);
    const min = Math.min(p.r, p.g, p.b);
    return (max - min) > 80 && max > 100;
  });
  console.log(`  饱和色像素(可能是标注元素): ${(saturated.length / pixels.length * 100).toFixed(1)}%`);

  // Categorize saturated colors
  const redPixels = saturated.filter(p => p.r > p.g + 40 && p.r > p.b + 40);
  const bluePixels = saturated.filter(p => p.b > p.r + 40 && p.b > p.g + 40);
  const greenPixels = saturated.filter(p => p.g > p.r + 40 && p.g > p.b + 40);
  if (redPixels.length > 0) console.log(`  红色元素: ${redPixels.length} (可能是标注线/圈)`);
  if (bluePixels.length > 0) console.log(`  蓝色元素: ${bluePixels.length}`);
  if (greenPixels.length > 0) console.log(`  绿色元素: ${greenPixels.length}`);

  // Analyze central region vs edge regions for layout structure
  const centerX1 = Math.floor(width * 0.2), centerX2 = Math.floor(width * 0.8);
  const centerY1 = Math.floor(height * 0.15), centerY2 = Math.floor(height * 0.85);
  const centerPixels = pixels.filter(p => p.x >= centerX1 && p.x <= centerX2 && p.y >= centerY1 && p.y <= centerY2);
  const edgePixels = pixels.filter(p => p.x < centerX1 || p.x > centerX2 || p.y < centerY1 || p.y > centerY2);

  const centerNonWhite = centerPixels.filter(p => p.r < 220 || p.g < 220 || p.b < 220);
  const edgeNonWhite = edgePixels.filter(p => p.r < 220 || p.g < 220 || p.b < 220);

  console.log(`\n--- 布局分析 ---`);
  console.log(`  中央区域(20-80%): ${centerPixels.length} 采样, 非白 ${centerNonWhite.length}`);
  console.log(`  边缘区域: ${edgePixels.length} 采样, 非白 ${edgeNonWhite.length}`);

  if (edgeNonWhite.length > edgePixels.length * 0.3) {
    console.log(`  => 边缘有密集内容(圆圈标注/文字可能在边缘)`);
  }
  if (centerNonWhite.length > centerPixels.length * 0.7) {
    console.log(`  => 中央有密集内容(产品图在中央)`);
  }

  // Analyze top-left, top-right, bottom-left, bottom-right quadrants
  const quadrants = [
    { name: "左上 TL", x1: 0, x2: Math.floor(width/2), y1: 0, y2: Math.floor(height/2) },
    { name: "右上 TR", x1: Math.floor(width/2), x2: width, y1: 0, y2: Math.floor(height/2) },
    { name: "左下 BL", x1: 0, x2: Math.floor(width/2), y1: Math.floor(height/2), y2: height },
    { name: "右下 BR", x1: Math.floor(width/2), x2: width, y1: Math.floor(height/2), y2: height },
  ];

  console.log(`\n--- 四象限分析 ---`);
  for (const q of quadrants) {
    const qPixels = pixels.filter(p => p.x >= q.x1 && p.x < q.x2 && p.y >= q.y1 && p.y < q.y2);
    const qNonWhite = qPixels.filter(p => p.r < 220 || p.g < 220 || p.b < 220);
    const qSaturated = qPixels.filter(p => {
      const max = Math.max(p.r, p.g, p.b);
      const min = Math.min(p.r, p.g, p.b);
      return (max - min) > 80 && max > 100;
    });
    console.log(`  ${q.name}: 非白=${(qNonWhite.length/qPixels.length*100).toFixed(0)}% 饱和=${(qSaturated.length/qPixels.length*100).toFixed(0)}%`);
  }

  // Line detection - sample rows and columns for color changes (indicating lines)
  console.log(`\n--- 线条检测 ---`);
  const lineRowSamples = [0.25, 0.5, 0.75].map(ratio => Math.floor(height * ratio));
  for (const rowY of lineRowSamples) {
    let transitions = 0;
    let lastColor = null;
    for (let x = 0; x < width; x += 5) {
      const idx = (rowY * width + x) * 3;
      if (idx + 2 < raw.length) {
        const col = `${Math.round(raw[idx]/64)*64},${Math.round(raw[idx+1]/64)*64},${Math.round(raw[idx+2]/64)*64}`;
        if (lastColor && col !== lastColor) transitions++;
        lastColor = col;
      }
    }
    console.log(`  行 y=${rowY}: ${transitions} 次颜色变化`);
  }
}

