  await analyzeImage("C:\\Users\\Administrator\\Desktop\\111\\Hefdd4c7ab4ec4fbc9906bf3e381ce4a06.jpg");
  await analyzeImage("C:\\Users\\Administrator\\Desktop\\222\\O1CN01L802zF1ETGQeGvjBS_!!2980740352-0-cib.jpg");
