const sharp = require("sharp");
const path = require("path");

async function deepAnalyze(filePath, label) {
  const meta = await sharp(filePath).metadata();
  const { width, height } = meta;
  const raw = await sharp(filePath).raw().toBuffer();

  console.log(`\n========== ${label} ==========`);

  // Build a color map of the image at reduced resolution
  const scale = 20;
  const gw = Math.floor(width / scale);
  const gh = Math.floor(height / scale);

  function getPixel(x, y) {
    const idx = (y * width + x) * 3;
    if (idx + 2 >= raw.length) return null;
    return { r: raw[idx], g: raw[idx + 1], b: raw[idx + 2] };
  }

  // Detect circles: scan for circular patterns of non-white pixels
  console.log("\n--- 圆圈/标注探测 ---");
  const circleCandidates = [];
  for (let y = 0; y < height; y += 10) {
    for (let x = 0; x < width; x += 10) {
      const c = getPixel(x, y);
      if (!c) continue;
      const isWhite = c.r > 220 && c.g > 220 && c.b > 220;
      const isDark = c.r < 80 && c.g < 80 && c.b < 80;
      if (isDark) {
        // Check if this dark pixel is part of a small cluster (potential text or circle outline)
        let darkCount = 0;
        for (let dy = -8; dy <= 8; dy += 2) {
          for (let dx = -8; dx <= 8; dx += 2) {
            const nc = getPixel(x + dx, y + dy);
            if (nc && nc.r < 80 && nc.g < 80 && nc.b < 80) darkCount++;
          }
        }
        if (darkCount > 15) {
          circleCandidates.push({ x, y, density: darkCount });
        }
      }
    }
  }

  // Cluster circle candidates
  const clusters = [];
  for (const pt of circleCandidates) {
    let found = false;
    for (const cl of clusters) {
      const dist = Math.sqrt((cl.x - pt.x) ** 2 + (cl.y - pt.y) ** 2);
      if (dist < 40) { found = true; cl.count++; cl.x = (cl.x * cl.count + pt.x) / (cl.count + 1); cl.y = (cl.y * cl.count + pt.y) / (cl.count + 1); break; }
    }
    if (!found) clusters.push({ x: pt.x, y: pt.y, count: 1 });
  }

  const significantClusters = clusters.filter(c => c.count > 3).sort((a, b) => a.y - b.y);
  console.log(`  检测到 ${significantClusters.length} 个内容区域:`);
  const zones = ["顶部", "中上", "中部", "中下", "底部"];
  for (const cl of significantClusters) {
    const zoneIdx = Math.min(4, Math.floor((cl.y / height) * 5));
    const side = cl.x < width / 3 ? "左侧" : cl.x < width * 2 / 3 ? "中央" : "右侧";
    console.log(`  位置 (${Math.round(cl.x)},${Math.round(cl.y)}) ${zones[zoneIdx]}/${side} 密度=${cl.count}`);
  }

  // Detect colored annotation lines (non-white, non-product colored pixels)
  console.log("\n--- 标注线/箭头检测 ---");
  const lineColors = [];
  for (let y = 10; y < height; y += 4) {
    for (let x = 10; x < width; x += 4) {
      const c = getPixel(x, y);
      if (!c) continue;
      const isWhite = c.r > 220 && c.g > 220 && c.b > 220;
      const isProduct = c.r > 180 && c.g > 160 && c.b > 120; // beige product tones
      if (!isWhite && !isProduct) {
        const sat = Math.max(c.r, c.g, c.b) - Math.min(c.r, c.g, c.b);
        if (sat > 40) {
          lineColors.push({ r: c.r, g: c.g, b: c.b, x, y });
        }
      }
    }
  }

  // Group by color
  const colorGroups = {};
  for (const lc of lineColors) {
    const key = `${Math.round(lc.r / 40) * 40},${Math.round(lc.g / 40) * 40},${Math.round(lc.b / 40) * 40}`;
    if (!colorGroups[key]) colorGroups[key] = [];
    colorGroups[key].push(lc);
  }

  const sortedGroups = Object.entries(colorGroups)
    .map(([key, pts]) => ({ color: key, count: pts.length, pts }))
    .filter(g => g.count > 5)
    .sort((a, b) => b.count - a.count);

  for (const g of sortedGroups.slice(0, 6)) {
    const xs = g.pts.map(p => p.x);
    const ys = g.pts.map(p => p.y);
    const minX = Math.min(...xs), maxX = Math.max(...xs);
    const minY = Math.min(...ys), maxY = Math.max(...ys);
    const area = ((maxX - minX) / width * 100).toFixed(0) + "% x " + ((maxY - minY) / height * 100).toFixed(0) + "%";
    console.log(`  颜色 rgb(${g.color}) ${g.count}像素 区域=${area} ${minX < width*0.3 ? "偏左" : minX > width*0.7 ? "偏右" : "居中"} ${minY < height*0.3 ? "偏上" : minY > height*0.7 ? "偏下" : "居中"}`);
  }

  // Check for Chinese characters in the reference image
  // Chinese text typically appears as dense dark pixel clusters in specific regions
  console.log("\n--- 文字区域检测 ---");
  for (let y = 0; y < height; y += 30) {
    for (let x = 0; x < width; x += 30) {
      if (x > width - 30 || y > height - 30) continue;
      let darkCount = 0, totalCount = 0;
      for (let dy = 0; dy < 20; dy += 2) {
        for (let dx = 0; dx < 20; dx += 2) {
          const c = getPixel(x + dx, y + dy);
          if (!c) continue;
          totalCount++;
          if (c.r < 80 && c.g < 80 && c.b < 80) darkCount++;
        }
      }
      if (darkCount > 10 && darkCount < totalCount * 0.6) {
        const zoneIdx = Math.min(4, Math.floor((y / height) * 5));
        const side = x < width / 3 ? "左" : x < width * 2 / 3 ? "中" : "右";
        console.log(`  文字区域 (${x},${y}) ${zones[zoneIdx]}${side} 暗像素=${darkCount}/${totalCount}`);
      }
    }
  }

  // Precise row-by-row scanning for layout boundary detection
  console.log("\n--- 布局边界 ---");
  // Find horizontal bands with significant content changes
  const rowChanges = [];
  for (let y = 0; y < height; y += 5) {
    let nonWhite = 0;
    for (let x = 0; x < width; x += 5) {
      const c = getPixel(x, y);
      if (c && (c.r < 210 || c.g < 210 || c.b < 210)) nonWhite++;
    }
    rowChanges.push(nonWhite);
  }

  // Find transitions (where content density changes significantly)
  let prevDensity = 0;
  const transitions = [];
  for (let y = 0; y < rowChanges.length; y += 10) {
    const density = rowChanges[y];
    const diff = Math.abs(density - prevDensity);
    if (diff > 15 && prevDensity > 0) {
      transitions.push({ y: y * 5, density, prevDensity });
    }
    prevDensity = density;
  }

  // Report significant content bands
  let inBand = false;
  let bandStart = 0;
  let bandContent = 0;
  for (let y = 0; y < height; y += 10) {
    const idx = Math.floor(y / 5);
    if (idx >= rowChanges.length) break;
    const hasContent = rowChanges[idx] > 20;
    if (hasContent && !inBand) { inBand = true; bandStart = y; bandContent = 0; }
    if (hasContent) bandContent += rowChanges[idx];
    if (!hasContent && inBand) {
      const pct = Math.floor(bandStart / height * 100);
      const endPct = Math.floor((y) / height * 100);
      console.log(`  内容带 ${pct}-${endPct}% (y=${bandStart}-${y})`);
      inBand = false;
    }
  }
  if (inBand) console.log(`  内容带 ${Math.floor(bandStart/height*100)}-100% (y=${bandStart}-${height})`);
}

async function main() {
  await deepAnalyze(
    "C:\\Users\\Administrator\\Desktop\\111\\Hefdd4c7ab4ec4fbc9906bf3e381ce4a06.jpg",
    "参考图 - 标注风格"
  );
  await deepAnalyze(
    "C:\\Users\\Administrator\\Desktop\\222\\O1CN01L802zF1ETGQeGvjBS_!!2980740352-0-cib.jpg",
    "产品图1"
  );
  await deepAnalyze(
    "C:\\Users\\Administrator\\Desktop\\222\\O1CN01MLylkd1ETGQd9k9wH_!!2980740352-0-cib.jpg",
    "产品图2"
  );
}

main().catch(console.error);

