const sharp = require("sharp");
const path = require("path");

async function detectFeatures(filePath, label) {
  const meta = await sharp(filePath).metadata();
  const { width, height } = meta;
  const raw = await sharp(filePath).raw().toBuffer();

  console.log(`\n========== ${label} 特征检测 ==========`);

  function getPixel(x, y) {
    x = Math.round(x); y = Math.round(y);
    if (x < 0 || x >= width || y < 0 || y >= height) return null;
    const idx = (y * width + x) * 3;
    return { r: raw[idx], g: raw[idx + 1], b: raw[idx + 2] };
  }

  // 1. Find vertical edges (potential zipper line in center)
  console.log("\n--- 垂直边缘检测(找拉链) ---");
  const centerX = Math.floor(width / 2);
  for (let y = 100; y < height - 100; y += 50) {
    let maxDiff = 0, maxX = 0;
    // Scan horizontally around center for sharp color transitions
    for (let x = centerX - 100; x < centerX + 100; x += 2) {
      const c1 = getPixel(x - 3, y);
      const c2 = getPixel(x + 3, y);
      if (!c1 || !c2) continue;
      const diff = Math.abs(c1.r - c2.r) + Math.abs(c1.g - c2.g) + Math.abs(c1.b - c2.b);
      if (diff > maxDiff) { maxDiff = diff; maxX = x; }
    }
    if (maxDiff > 30) {
      console.log(`  y=${y}: 最强垂直边缘 x=${maxX} (对比度=${maxDiff}) — ${maxDiff > 50 ? "拉链/缝线" : "可能是褶皱"}`);
    }
  }

  // 2. Find horizontal edges (potential collar, hem, cuffs)
  console.log("\n--- 水平边缘检测(找领口/袖口/脚口) ---");
  for (let x = 100; x < width - 100; x += 100) {
    let maxDiff = 0, maxY = 0;
    for (let y = 20; y < height - 20; y += 2) {
      const c1 = getPixel(x, y - 3);
      const c2 = getPixel(x, y + 3);
      if (!c1 || !c2) continue;
      const diff = Math.abs(c1.r - c2.r) + Math.abs(c1.g - c2.g) + Math.abs(c1.b - c2.b);
      if (diff > maxDiff) { maxDiff = diff; maxY = y; }
    }
    if (maxDiff > 40) {
      const zone = maxY < height * 0.3 ? "领口/肩部" : maxY < height * 0.5 ? "胸部" : maxY < height * 0.7 ? "腹部" : "脚口/底部";
      console.log(`  x=${x}: 最强水平边缘 y=${maxY} (对比度=${maxDiff}) — ${zone}`);
    }
  }

  // 3. Find extremity boundaries (leftmost/rightmost non-white pixels per row)
  console.log("\n--- 产品轮廓检测 ---");
  const leftEdges = [], rightEdges = [], topEdges = [], bottomEdges = [];

  function isProduct(r, g, b) {
    // Product is warm beige tones; ignore pure white
    return !(r > 240 && g > 240 && b > 240);
  }

  // Find leftmost product pixel per row
  for (let y = 50; y < height - 50; y += 10) {
    for (let x = 5; x < width; x += 2) {
      const c = getPixel(x, y);
      if (c && isProduct(c.r, c.g, c.b)) {
        // Check if this is truly edge (neighbor is significantly different)
        const cLeft = getPixel(x - 5, y);
        if (cLeft && !isProduct(cLeft.r, cLeft.g, cLeft.b)) {
          leftEdges.push({ x, y });
        }
        break;
      }
    }
    // Find rightmost
    for (let x = width - 5; x > 0; x -= 2) {
      const c = getPixel(x, y);
      if (c && isProduct(c.r, c.g, c.b)) {
        const cRight = getPixel(x + 5, y);
        if (cRight && !isProduct(cRight.r, cRight.g, cRight.b)) {
          rightEdges.push({ x, y });
        }
        break;
      }
    }
  }

  if (leftEdges.length > 0) {
    const minX = Math.min(...leftEdges.map(e => e.x));
    const yAtMinX = leftEdges.find(e => e.x === minX)?.y || 0;
    console.log(`  最左边缘: x=${minX} (y≈${yAtMinX}) — ${yAtMinX < height*0.4 ? "左袖口" : "左裤脚"}`);
  }
  if (rightEdges.length > 0) {
    const maxX = Math.max(...rightEdges.map(e => e.x));
    const yAtMaxX = rightEdges.find(e => e.x === maxX)?.y || 0;
    console.log(`  最右边缘: x=${maxX} (y≈${yAtMaxX}) — ${yAtMaxX < height*0.4 ? "右袖口" : "右裤脚"}`);
  }

  // Find topmost/bottommost product pixels
  for (let x = centerX - 150; x <= centerX + 150; x += 10) {
    for (let y = 5; y < height; y += 2) {
      const c = getPixel(x, y);
      if (c && isProduct(c.r, c.g, c.b)) {
        topEdges.push({ x, y });
        break;
      }
    }
    for (let y = height - 5; y > 0; y -= 2) {
      const c = getPixel(x, y);
      if (c && isProduct(c.r, c.g, c.b)) {
        bottomEdges.push({ x, y });
        break;
      }
    }
  }

  if (topEdges.length > 0) {
    const avgY = Math.round(topEdges.reduce((s, e) => s + e.y, 0) / topEdges.length);
    console.log(`  产品顶部: y≈${avgY} (领口位置)`);
  }
  if (bottomEdges.length > 0) {
    const avgY = Math.round(bottomEdges.reduce((s, e) => s + e.y, 0) / bottomEdges.length);
    console.log(`  产品底部: y≈${avgY} (脚口位置)`);
  }

  // 4. Color analysis for specific features
  console.log("\n--- 颜色特征区域 ---");
  // Darker regions might be zipper, labels, etc.
  const darkRegions = [];
  for (let y = 50; y < height - 50; y += 15) {
    for (let x = 50; x < width - 50; x += 15) {
      const c = getPixel(x, y);
      if (!c) continue;
      const brightness = (c.r + c.g + c.b) / 3;
      if (brightness < 120) {
        // Check if it's part of a larger dark region
        let darkCount = 0;
        for (let dy = -10; dy <= 10; dy += 5)
          for (let dx = -10; dx <= 10; dx += 5) {
            const nc = getPixel(x + dx, y + dy);
            if (nc && (nc.r + nc.g + nc.b) / 3 < 150) darkCount++;
          }
        if (darkCount > 5) darkRegions.push({ x, y, brightness });
      }
    }
  }

  const darkClusters = [];
  for (const d of darkRegions) {
    let found = false;
    for (const cl of darkClusters) {
      if (Math.abs(cl.x - d.x) < 30 && Math.abs(cl.y - d.y) < 30) {
        cl.count++; cl.x = (cl.x * cl.count + d.x) / (cl.count + 1);
        cl.y = (cl.y * cl.count + d.y) / (cl.count + 1);
        found = true; break;
      }
    }
    if (!found) darkClusters.push({ x: d.x, y: d.y, count: 1 });
  }

  const significantDark = darkClusters.filter(c => c.count > 3).sort((a, b) => a.y - b.y);
  for (const d of significantDark) {
    const zone = d.y < height*0.3 ? "领口" : d.y < height*0.45 ? "胸部" : d.y < height*0.6 ? "腹部/拉链" : d.y < height*0.8 ? "大腿" : "脚口";
    const side = d.x < width*0.3 ? "偏左" : d.x > width*0.7 ? "偏右" : "居中";
    console.log(`  深色区域 (${Math.round(d.x)},${Math.round(d.y)}) ${zone}/${side} 亮度=${d.count}`);
  }

  // 5. Estimate product body measurements
  console.log("\n--- 产品体态估计 ---");
  const bodyWidth = rightEdges.length > 0 && leftEdges.length > 0 ?
    Math.round(Math.max(...rightEdges.map(e => e.x)) - Math.min(...leftEdges.map(e => e.x))) : "N/A";
  console.log(`  产品宽度: ~${bodyWidth}px`);
  const bodyHeight = topEdges.length > 0 && bottomEdges.length > 0 ?
    Math.round(Math.max(...bottomEdges.map(e => e.y)) - Math.min(...topEdges.map(e => e.y))) : "N/A";
  console.log(`  产品高度: ~${bodyHeight}px`);

  // 6. Find zipper by looking for vertical line of consistent high-contrast
  console.log("\n--- 拉链精确定位 ---");
  const zipCandidates = [];
  for (let y = 100; y < height - 50; y += 5) {
    let bestX = centerX, bestScore = 0;
    for (let x = centerX - 80; x < centerX + 80; x += 1) {
      const c = getPixel(x, y);
      const cLeft = getPixel(x - 4, y);
      const cRight = getPixel(x + 4, y);
      if (!c || !cLeft || !cRight) continue;
      const score = Math.abs(cLeft.r - cRight.r) + Math.abs(cLeft.g - cRight.g) + Math.abs(cLeft.b - cRight.b);
      if (score > bestScore) { bestScore = score; bestX = x; }
    }
    if (bestScore > 25) zipCandidates.push({ x: bestX, y, score: bestScore });
  }

  if (zipCandidates.length > 5) {
    const avgX = Math.round(zipCandidates.reduce((s, c) => s + c.x, 0) / zipCandidates.length);
    const yStart = zipCandidates[0].y;
    const yEnd = zipCandidates[zipCandidates.length - 1].y;
    console.log(`  拉链位置: x≈${avgX}, y=${yStart}-${yEnd}`);
    console.log(`  拉链长度: ~${yEnd - yStart}px`);
    console.log(`  拉链起始: 领口下 ~${yStart}px`);
    console.log(`  拉链终点: ~${yEnd}px`);
  }
}

async function main() {
  await detectFeatures(
    "C:\\Users\\Administrator\\Desktop\\222\\O1CN01L802zF1ETGQeGvjBS_!!2980740352-0-cib.jpg",
    "产品图1（正面）"
  );
