const sharp = require("sharp");
const fs = require("fs");
const path = require("path");

const CANVAS_W = 1600;
const CANVAS_H = 1600;
const OUTPUT = "D:\\ClaudeWorkspace\\01_P4P\\主图素材\\连体衣_主图_标注版.png";

// Product image coordinate system (800x800) → mapped positions
// Detected features from analysis:
const FEATURES = {
  zipper:       { px: 421, py: 420, label: "双向拉链\nTwo-way Zipper" },
  handCover:    { px: 100, py: 300, label: "手脚翻转覆盖\nFold-over Hand & Foot Cuffs" },
  footCover:    { px: 175, py: 690, label: "脚口翻转设计\nFold-over Foot Cuffs" },
  zipperGuard:  { px: 421, py: 140, label: "领口拉链盖保护\nZipper Guard Protection" },
  sizeChart:    { px: 320, py: 80,  label: "领口尺码标\nSize Chart Label" },
};

// Annotation circle positions on canvas (where to place zoomed circles)
const CIRCLES = {
  zipper:      { cx: 1350, cy: 700, r: 100 },
  handCover:   { cx: 200,  cy: 550, r: 100 },
  footCover:   { cx: 300,  cy: 1350, r: 100 },
  zipperGuard: { cx: 1350, cy: 350, r: 100 },
  sizeChart:   { cx: 800,  cy: 1480, r: 80 },
};

// Product placement on canvas
const PROD_SCALE = 0.95; // scale from 800 to canvas
const prodW = Math.round(800 * PROD_SCALE);
const prodH = Math.round(800 * PROD_SCALE);
const prodX = Math.round((CANVAS_W - prodW) / 2); // center
const prodY = Math.round(300);

// Map product coordinate (800x800) to canvas coordinate
function mapToCanvas(px, py) {
  const scale = PROD_SCALE;
  return {
    x: Math.round(prodX + px * scale),
    y: Math.round(prodY + py * scale),
  };
}

async function main() {
  const productPath = "C:\\Users\\Administrator\\Desktop\\222\\O1CN01L802zF1ETGQeGvjBS_!!2980740352-0-cib.jpg";

  // Step 1: Create base white canvas
  console.log("Creating canvas...");
  const canvas = sharp({
    create: {
      width: CANVAS_W,
      height: CANVAS_H,
      channels: 4,
      background: { r: 252, g: 250, b: 240, alpha: 1 }, // warm white like reference
    },
  });

  // Step 2: Place product image
  console.log("Placing product image...");
  const productResized = await sharp(productPath)
    .resize(prodW, prodH, { fit: "fill" })
    .toBuffer();

  // Step 3: Create zoomed detail circles
  console.log("Creating detail callouts...");
  const composited = [];
  composited.push({ input: productResized, top: prodY, left: prodX });

  const detailSize = 50; // extract region
  const circleDiam = 200; // display size

  for (const [key, feat] of Object.entries(FEATURES)) {
    const circle = CIRCLES[key];
    const rx = Math.max(0, Math.min(750, feat.px - detailSize / 2));
    const ry = Math.max(0, Math.min(750, feat.py - detailSize / 2));

    try {
      const detail = await sharp(productPath)
        .extract({ left: Math.round(rx), top: Math.round(ry), width: detailSize, height: detailSize })
        .resize(circleDiam, circleDiam)
        .toBuffer();

      // Create circular mask
      const svgMask = Buffer.from(
        `<svg width="${circleDiam}" height="${circleDiam}">
          <circle cx="${circleDiam/2}" cy="${circleDiam/2}" r="${circleDiam/2}" fill="white"/>
        </svg>`
      );

      const circled = await sharp(detail)
        .composite([{ input: svgMask, top: 0, left: 0, blend: "dest-in" }])
        .png()
        .toBuffer();

      composited.push({
        input: circled,
        top: circle.cy - circle.r,
        left: circle.cx - circle.r,
      });
      console.log(`  ${key}: detail region (${rx},${ry}) → canvas (${circle.cx},${circle.cy})`);
    } catch (e) {
      console.error(`  ${key} failed: ${e.message}`);
    }
  }

  // Step 4: Create SVG overlay with dotted lines, circle borders, text
  console.log("Creating annotation overlay...");
  let svgLines = `<svg width="${CANVAS_W}" height="${CANVAS_H}" xmlns="http://www.w3.org/2000/svg">`;

  // Add a subtle top title
  svgLines += `<text x="800" y="60" text-anchor="middle" font-family="Arial,sans-serif" font-size="32" fill="#333" font-weight="bold">PRODUCT DETAILS — 婴儿连体衣 定制细节展示</text>`;
  svgLines += `<text x="800" y="95" text-anchor="middle" font-family="Arial,sans-serif" font-size="18" fill="#888">Baby Romper Customization Details</text>`;

  // Dotted lines and circle annotations
  const lineColor = "rgba(80,160,80,0.8)";
  const lineWidth = 2.5;
  const dashArray = "8,6";

  for (const [key, feat] of Object.entries(FEATURES)) {
    const canvasPt = mapToCanvas(feat.px, feat.py);
    const circle = CIRCLES[key];

    // Dotted line from product feature to annotation circle edge
    const dx = circle.cx - canvasPt.x;
    const dy = circle.cy - canvasPt.y;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist === 0) continue;

    // Find the point on the circle edge closest to the feature
    const edgeX = Math.round(circle.cx - (dx / dist) * circle.r);
    const edgeY = Math.round(circle.cy - (dy / dist) * circle.r);

    svgLines += `<line x1="${canvasPt.x}" y1="${canvasPt.y}" x2="${edgeX}" y2="${edgeY}" stroke="${lineColor}" stroke-width="${lineWidth}" stroke-dasharray="${dashArray}" />`;

    // Small dot at product feature point
    svgLines += `<circle cx="${canvasPt.x}" cy="${canvasPt.y}" r="5" fill="${lineColor}" />`;

    // Circle border
    svgLines += `<circle cx="${circle.cx}" cy="${circle.cy}" r="${circle.r}" fill="none" stroke="${lineColor}" stroke-width="3" stroke-dasharray="6,4" />`;

    // Label text below the circle
    const lines = feat.label.split("\n");
    lines.forEach((line, i) => {
      svgLines += `<text x="${circle.cx}" y="${circle.cy + circle.r + 24 + i * 22}" text-anchor="middle" font-family="Arial,sans-serif" font-size="14" fill="#444" font-weight="bold">${line}</text>`;
    });
  }

  // Add size chart area at bottom
  svgLines += `<rect x="600" y="1380" width="400" height="2" fill="#ddd" rx="1" />`;

  // Footer
  svgLines += `<text x="800" y="1560" text-anchor="middle" font-family="Arial,sans-serif" font-size="13" fill="#aaa">Yiyang Xiaoxingxing Garment Co., Ltd | OEM/ODM Professional Baby Products Manufacturer</text>`;

  svgLines += `</svg>`;

  // Composite everything
  console.log("Rendering final image...");
  const result = await canvas
    .composite([
      ...composited,
      {
        input: Buffer.from(svgLines),
        top: 0,
        left: 0,
        blend: "over",
      },
    ])
    .png()
    .toFile(OUTPUT);

  console.log(`\n✅ Done! Saved to: ${OUTPUT}`);
  console.log(`  Size: ${result.width}x${result.height}, ${result.size} bytes`);
}

main().catch(console.error);
